import{_ as i,o as a,c as s,a2 as t}from"./chunks/framework.C58al07P.js";const p=JSON.parse('{"title":"Pièces jointes","description":"","frontmatter":{},"headers":[],"relativePath":"fr/guide/attachments.md","filePath":"fr/guide/attachments.md"}'),l={name:"fr/guide/attachments.md"};function r(o,e,n,c,u,d){return a(),s("div",null,[...e[0]||(e[0]=[t('<h1 id="pieces-jointes" tabindex="-1">Pièces jointes <a class="header-anchor" href="#pieces-jointes" aria-label="Permalink to &quot;Pièces jointes&quot;">​</a></h1><p>La page <strong>Pièces jointes</strong> centralise toutes les pièces jointes de vos mails, qu&#39;ils soient dans Gmail ou dans vos archives locales.</p><hr><h2 id="deux-onglets" tabindex="-1">Deux onglets <a class="header-anchor" href="#deux-onglets" aria-label="Permalink to &quot;Deux onglets&quot;">​</a></h2><p>La page est divisée en deux onglets :</p><h3 id="archives-nas" tabindex="-1">Archives (NAS) <a class="header-anchor" href="#archives-nas" aria-label="Permalink to &quot;Archives (NAS)&quot;">​</a></h3><p>Les pièces jointes des mails archivés sur votre NAS. Elles sont stockées séparément des fichiers EML et indexées dans la base de données.</p><ul><li>Recherche par nom de fichier</li><li>Tri par taille ou par date</li><li>Téléchargement direct</li></ul><h3 id="gmail-live" tabindex="-1">Gmail (Live) <a class="header-anchor" href="#gmail-live" aria-label="Permalink to &quot;Gmail (Live)&quot;">​</a></h3><p>Les pièces jointes des mails encore dans votre boîte Gmail. Un scan est effectué via l&#39;API Gmail pour récupérer la liste.</p><ul><li>Scan à la demande</li><li>Tri par taille pour identifier les fichiers les plus volumineux</li><li>Navigation vers le mail dans Gmail</li></ul><blockquote><p>📸 <em>Capture d&#39;écran suggérée : page Pièces jointes avec les deux onglets Archives / Gmail, la liste des PJ et les boutons de tri</em></p></blockquote><hr><h2 id="recherche-et-tri" tabindex="-1">Recherche et tri <a class="header-anchor" href="#recherche-et-tri" aria-label="Permalink to &quot;Recherche et tri&quot;">​</a></h2><p>Vous pouvez :</p><ul><li><strong>Rechercher</strong> par nom de fichier (ex. : <code>facture</code>, <code>.pdf</code>, <code>photo.jpg</code>)</li><li><strong>Trier par taille</strong> : les plus gros fichiers en premier — idéal pour libérer de l&#39;espace</li><li><strong>Trier par date</strong> : les plus récents ou les plus anciens en premier</li><li><strong>Paginer</strong> : naviguez entre les pages de résultats</li></ul><hr><h2 id="telechargement" tabindex="-1">Téléchargement <a class="header-anchor" href="#telechargement" aria-label="Permalink to &quot;Téléchargement&quot;">​</a></h2><p>Cliquez sur le bouton <strong>Télécharger</strong> à côté d&#39;une pièce jointe pour la télécharger directement. Les pièces jointes archivées sont servies depuis le NAS, les pièces jointes Gmail sont récupérées via l&#39;API Gmail.</p><hr><h2 id="cas-d-usage" tabindex="-1">Cas d&#39;usage <a class="header-anchor" href="#cas-d-usage" aria-label="Permalink to &quot;Cas d&#39;usage&quot;">​</a></h2><ul><li><strong>Libérer de l&#39;espace Gmail</strong> : identifiez les pièces jointes les plus volumineuses, archivez les mails correspondants sur le NAS, puis supprimez-les de Gmail</li><li><strong>Retrouver un fichier</strong> : recherchez un nom de fichier dans les archives</li><li><strong>Audit de stockage</strong> : visualisez la répartition des types de pièces jointes</li></ul><hr><h2 id="deduplication-par-hash-de-contenu" tabindex="-1">Déduplication par hash de contenu <a class="header-anchor" href="#deduplication-par-hash-de-contenu" aria-label="Permalink to &quot;Déduplication par hash de contenu&quot;">​</a></h2><p>Nid déduplique automatiquement les pièces jointes identiques lors de l&#39;archivage. Chaque fichier est identifié par son hash SHA-256 : si deux mails contiennent exactement la même pièce jointe, le fichier n&#39;est stocké qu&#39;une seule fois sur le disque.</p><h3 id="statistiques" tabindex="-1">Statistiques <a class="header-anchor" href="#statistiques" aria-label="Permalink to &quot;Statistiques&quot;">​</a></h3><p>La carte <strong>Espace économisé</strong> affiche :</p><ul><li>Le volume d&#39;espace disque économisé grâce à la déduplication</li><li>Le nombre de fichiers dupliqués détectés</li><li>La couverture du hash (pourcentage de pièces jointes analysées)</li></ul><h3 id="backfill" tabindex="-1">Backfill <a class="header-anchor" href="#backfill" aria-label="Permalink to &quot;Backfill&quot;">​</a></h3><p>Si vous avez archivé des mails avant l&#39;activation de la déduplication, cliquez sur le bouton <strong>Analyser</strong> pour calculer les hash des pièces jointes existantes. Cette opération :</p><ol><li>Lit chaque fichier sur le stockage (local ou S3)</li><li>Calcule le hash SHA-256</li><li>Identifie les doublons et supprime les copies redondantes</li><li>Met à jour la base de données pour pointer vers le fichier unique</li></ol><blockquote><p>⚠️ Le backfill peut prendre du temps si vous avez beaucoup de pièces jointes archivées.</p></blockquote>',32)])])}const m=i(l,[["render",r]]);export{p as __pageData,m as default};
